import prometheus_client as pc
from flask import Flask, request

app = Flask(__name__)

# Prometheus metrics definitions
user_requests_total = pc.Counter(
    'http_user_requests_total',
    'Total HTTP requests made with label user_id and path',
    ['user_id', 'path']
)

# Use the metric in your views
@app.route('/')
def index():
    user_id = request.args.get('id')
    session_id = request.args.get('session_id')
    full_path = request.path

    # Create new metric for each unique user-path combination
    label_values = {
        'user_id': user_id,
        'path': full_path
    }
    user_requests_total.labels(**label_values).inc()

    return 'Hello World!'

# Initialize the metrics registry
pc.start_http_server(8000)

if __name__ == '__main__':
    app.run(debug=True)